previewCss:
.darma-loader-darma-custom-319 {
  color: var(--loader-color, #f97316);
  height: 54px;
  aspect-ratio: 1;
  position: relative;
  background: 
    conic-gradient(at 20px 40px,#0000 25%,var(--loader-secondary-color, #facc15) 0),
    conic-gradient(from -90deg at 40px 20px,#0000 75%,var(--loader-secondary-color, #facc15) 0);
  clip-path: inset(-100% 0);
}
.darma-loader-darma-custom-319:before {
  content: "";
  position: absolute;
  inset: auto 75% 0 0;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #f97316);
  animation: 
    darma-loader-darma-custom-319-l12-0 .5s cubic-bezier(0,600,1,600) infinite,
    darma-loader-darma-custom-319-l12-1  2s linear infinite;
}
@keyframes darma-loader-darma-custom-319-l12-0 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}
@keyframes darma-loader-darma-custom-319-l12-1 {
  0% {translate: -18px -80px}
  to {translate:  62px   0}
}

